<template><el-card><template #header><b>敏感数据导出申请</b></template><el-alert title="敏感数据导出需要提交申请并经过审批，所有导出和下载行为均会记录审计日志。" type="warning" show-icon/><el-form label-width="120px" style="max-width:720px;margin-top:20px"><el-form-item label="模块"><el-select v-model="form.module"><el-option v-for="x in modules" :key="x" :value="x"/></el-select></el-form-item><el-form-item label="区划条件"><el-input v-model="regionCode"/></el-form-item><el-form-item label="导出字段"><el-checkbox-group v-model="form.fields"><el-checkbox v-for="x in fields[form.module]" :key="x" :value="x">{{x}}</el-checkbox></el-checkbox-group></el-form-item><el-form-item label="预计行数"><el-input-number v-model="form.expectedRowLimit" :min="1" :max="20000"/></el-form-item><el-form-item label="标题"><el-input v-model="form.title"/></el-form-item><el-form-item label="申请理由"><el-input v-model="form.reason" type="textarea"/></el-form-item><el-form-item><el-button type="primary" @click="save">提交申请草稿</el-button></el-form-item></el-form></el-card></template>
<script setup>import{reactive,ref}from'vue';import{useRouter}from'vue-router';import{ElMessage}from'element-plus';import{sensitiveApply}from'../../api/exports';const router=useRouter(),regionCode=ref(''),modules=['PERSON','HOUSEHOLD','MIGRATION','RESIDENCE_ARCHIVE','CANCELLATION','FLOATING_POPULATION','RESIDENCE_PERMIT','OPERATION_LOG'],fields={PERSON:['name','identityNo','phone','registeredAddress','regionCode'],HOUSEHOLD:['householdNo','address','regionCode','status'],MIGRATION:['applicationNo','businessType','status','regionCode'],RESIDENCE_ARCHIVE:['name','identityNo','registeredAddress','regionCode'],CANCELLATION:['cancellationNo','name','identityNo','registeredAddress'],FLOATING_POPULATION:['registrationNo','name','identityNo','phone','registeredAddress'],RESIDENCE_PERMIT:['permitNo','name','identityNo','phone','registeredAddress','validUntil'],OPERATION_LOG:['operationType','moduleName','operationTime','operationResult']},form=reactive({module:'PERSON',filters:{},fields:['name','identityNo'],reason:'',expectedRowLimit:1000,title:'敏感数据导出申请',remark:''});async function save(){form.filters=regionCode.value?{regionCode:regionCode.value}:{};const id=await sensitiveApply(form);ElMessage.success('申请草稿已创建');router.push('/exports/applications/'+id)}</script>
